const HEAT_COLORS={hot:{pin:"#ef4444",bg:"rgba(239,68,68,0.10)",border:"rgba(239,68,68,0.3)",glow:"0 0 20px rgba(239,68,68,0.2)"},warm:{pin:"#f59e0b",bg:"rgba(245,158,11,0.08)",border:"rgba(245,158,11,0.25)",glow:"0 0 14px rgba(245,158,11,0.15)"},cool:{pin:"#6366f1",bg:"rgba(99,102,241,0.06)",border:"rgba(99,102,241,0.2)",glow:"none"},};const CATEGORY_ICONS={"Cantine":"🍽️","Infrastructure":"🏗️","Vie scolaire":"📚","Pédagogie":"🎓","Numérique":"💻","Bien-être":"🌿","Autre":"📌",};const grid=document.getElementById("display-grid");const countEl=document.getElementById("display-count");const header=document.querySelector(".display-header");const waitingEl=document.getElementById("display-waiting");const waitingTitleEl=document.getElementById("waiting-title");const waitingTextEl=document.getElementById("waiting-text");let currentData=[];let currentProposal=null;let currentCritical=[];let currentMode="normal";let currentPriorityAnnouncement=null;async function checkDisplayMode(){try{const res=await fetch("/api/settings/public");const settings=await res.json();busSettings={bus_schedule:settings.bus_schedule||[],bus_force_display:settings.bus_force_display||false,bus_force_display_until:settings.bus_force_display_until||"",bus_alternance_enabled:settings.bus_alternance_enabled||false,bus_alternance_interval_sec:settings.bus_alternance_interval_sec||60,feature_bus_enabled:settings.feature_bus_enabled!==false,};const newMode=settings.display_mode||"normal";if(newMode!==currentMode){currentMode=newMode;applyDisplayMode(settings);}else if(newMode==="waiting"){waitingTitleEl.textContent=settings.display_waiting_title||"Boîte à Idées";waitingTextEl.textContent=settings.display_waiting_text||"";}}catch(e){}}
function applyDisplayMode(settings){if(currentPriorityAnnouncement)return;if(currentMode==="waiting"){grid.classList.add("hidden");header.classList.add("hidden");annContainer.classList.add("hidden");document.getElementById("display-completed-banner")?.classList.add("hidden");waitingEl.classList.remove("hidden");waitingTitleEl.textContent=settings.display_waiting_title||"Boîte à Idées";waitingTextEl.textContent=settings.display_waiting_text||"";}else{grid.classList.remove("hidden");header.classList.remove("hidden");annContainer.classList.remove("hidden");document.getElementById("display-completed-banner")?.classList.remove("hidden");waitingEl.classList.add("hidden");}}
async function fetchPriorityAnnouncement(){try{const res=await fetch("/api/display/priority-announcement");const data=await res.json();if(data&&data.id){currentPriorityAnnouncement=data;showPriorityAnnouncement(data);}else{if(currentPriorityAnnouncement){hidePriorityAnnouncementWithAnimation();}
currentPriorityAnnouncement=null;}}catch(e){if(currentPriorityAnnouncement)hidePriorityAnnouncementWithAnimation();currentPriorityAnnouncement=null;}}
