async function fetchSuggestions(){if(currentPriorityAnnouncement)return;if(currentMode!=="normal")return;try{const[suggestionsRes,proposalRes,criticalRes]=await Promise.all([fetch("/api/display/suggestions"),fetch("/api/official-proposal"),fetch("/api/display/critical-moments"),]);const suggestions=await suggestionsRes.json();const proposal=await proposalRes.json();const critical=await criticalRes.json();updateDisplay(suggestions,proposal,critical);}catch(e){console.error(e);}}
function updateDisplay(suggestions,proposal,critical){const total=suggestions.length+(proposal?1:0);countEl.textContent=`${total} element${total !== 1 ? "s" : ""}`;updateCriticalBanner(critical);updateProposalCard(proposal);const existingIds=new Set(currentData.map((s)=>s.id));const newIds=new Set(suggestions.map((s)=>s.id));suggestions.forEach((s,i)=>{const card=document.getElementById(`display-card-${s.id}`);if(card){updateCard(card,s);card.style.order=i;}else{const newCard=createCard(s,i);grid.appendChild(newCard);}});existingIds.forEach((id)=>{if(!newIds.has(id)){const card=document.getElementById(`display-card-${id}`);if(card){card.classList.add("display-card-exit");setTimeout(()=>card.remove(),500);}}});currentData=suggestions;}
